// Emit one output item per PDF attachment found in the email so that
// multi-ticket emails (e.g. two separate seat reservations in one booking)
// each become their own VoucherVault item in a single workflow run.
//
// Each output item keeps the full email JSON (id, subject, from, body)
// so downstream nodes can still access those fields, plus a 'file' binary
// property pointing at this particular PDF.
const results = [];
for (const emailItem of $input.all()) {
  const binary = emailItem.binary || {};
  const pdfKeys = Object.keys(binary).filter((key) => {
    const b = binary[key];
    return (b.mimeType || '').toLowerCase().includes('pdf')
      || (b.fileName || '').toLowerCase().endsWith('.pdf');
  });
  if (pdfKeys.length === 0) {
    // No PDFs — emit a sentinel so the Has PDF? node can route to the skip branch
    results.push({ json: { ...emailItem.json, _pdf_count: 0 }, binary: {} });
  } else {
    for (const key of pdfKeys) {
      const newBinary = { file: emailItem.binary[key] };
      results.push({ json: { ...emailItem.json, _pdf_count: pdfKeys.length }, binary: newBinary });
    }
  }
}
return results;

// Mine the email subject and plaintext body for fields that VoucherVault
// can use directly — text from the email is more reliable than vision-OCR
// on a rasterised page, and it's free (no API call). The server-side OCR
// still fills in whatever we miss here.
//
// Fields we try to extract:
//   issuer         — inferred from the From address
//   order_id       — booking/order reference number
//   journey_origin / journey_destination — from the email subject line
//   travel_date    — date of travel in YYYY-MM-DD format
const item = $input.first();
const subject = (item.json.subject || '').trim();
const body    = (item.json.textPlain || item.json.snippet || '').slice(0, 4000);
const from    = (item.json.from || '').toLowerCase();
const combined = subject + ' ' + body;

const extracted = {};

// Issuer from sender domain
if (from.includes('greateranglia'))   extracted.issuer = 'Greater Anglia';
else if (from.includes('trainline')) extracted.issuer = 'Trainline';
else if (from.includes('omio'))      extracted.issuer = 'Omio';
else if (from.includes('uber'))      extracted.issuer = 'Uber';
else if (from.includes('avanti'))    extracted.issuer = 'Avanti West Coast';
else if (from.includes('lner'))      extracted.issuer = 'LNER';
else if (from.includes('gwr'))       extracted.issuer = 'Great Western Railway';

// Order / booking reference: 6-12 uppercase alphanumeric chars preceded by a keyword
const orderMatch = combined.match(
  /(?:booking|order|ref(?:erence)?|confirmation)[\s:]*([A-Z0-9]{5,12})/i
);
if (orderMatch) extracted.order_id = orderMatch[1].toUpperCase();

// Route from subject — e.g. "Ipswich to London Liverpool Street - Booking confirmation"
const routeMatch = subject.match(/:\s*(.+?)\s+to\s+(.+?)\s*[-–—|]/i)
  || subject.match(/^(.+?)\s+to\s+(.+?)(?:\s*[-–—|]|$)/i);
if (routeMatch) {
  extracted.journey_origin      = routeMatch[1].trim();
  extracted.journey_destination = routeMatch[2].trim();
}

// Travel date: look for DD Month YYYY or DD/MM/YYYY or YYYY-MM-DD
const datePatterns = [
  /(\d{1,2}\s+(?:Jan(?:uary)?|Feb(?:ruary)?|Mar(?:ch)?|Apr(?:il)?|May|Jun(?:e)?|Jul(?:y)?|Aug(?:ust)?|Sep(?:tember)?|Oct(?:ober)?|Nov(?:ember)?|Dec(?:ember)?)\s+\d{4})/i,
  /(\d{1,2}[\/\-]\d{1,2}[\/\-]\d{2,4})/,
  /(\d{4}-\d{2}-\d{2})/,
];
for (const pat of datePatterns) {
  const m = combined.match(pat);
  if (m) {
    const raw = m[1];
    // Try to normalise to YYYY-MM-DD
    const parsed = new Date(raw);
    if (!isNaN(parsed.getTime())) {
      extracted.travel_date = parsed.toISOString().slice(0, 10);
    } else {
      extracted.travel_date = raw;  // leave as-is; server OCR will interpret
    }
    break;
  }
}

return [{ ...item, json: { ...item.json, _extracted: extracted } }];

